async (page) => {
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ equipment: s.equipment, player_position: s.player_position, player_stats: s.player_stats });
  });
  return state;
}
